// Kill-switch: this legacy custom SW was stuck cache-first on "pewil-v1"
// and never invalidated, so phones that registered it kept serving the
// old shell across deploys. On next visit, unregister ourselves, wipe
// every cache, and force a reload so the app registers the real SW
// (/service-worker.js generated by Workbox) instead.
self.addEventListener("install", () => { self.skipWaiting(); });
self.addEventListener("activate", (e) => {
  e.waitUntil((async () => {
    try {
      const keys = await caches.keys();
      await Promise.all(keys.map((k) => caches.delete(k)));
    } catch (err) { /* best-effort */ }
    try { await self.registration.unregister(); } catch (err) { /* best-effort */ }
    const clients = await self.clients.matchAll({ type: "window" });
    for (const c of clients) {
      try { c.navigate(c.url); } catch (err) { /* best-effort */ }
    }
  })());
});
// Always go to network; never serve from the dead cache.
self.addEventListener("fetch", (e) => { e.respondWith(fetch(e.request)); });
